import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>
          <Typewriter
            options={{
              loop: true,
            }}
            onInit={(typewriter) => {
              typewriter
                .typeString(
                  "Hello Am Burgeon a web dev, i am passionate about creating interesting Web Pages"
                )
                .callFunction(() => {
                  console.log("String typed out!");
                })

                .pauseFor(5)
                .deleteAll()
                .callFunction(() => {
                  console.log("All strings were deleted");
                })
                .start();
            }}
          />
        </h1>

        <Navbar />
      </header>
    </div>
  );
}

export default App;

const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>Am Burgeon</span>
        </h1>
        {}
      </div>
    </>
  );
};
const Navbar = () => {};
